function doPost(e) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
  const data = JSON.parse(e.postData.contents);

  // ── 1. GUARDAR EN GOOGLE SHEETS ──
  const emailTo        = data._emailTo;
  const nombreCompleto = data._nombreCompleto;
  const sendEmail      = data._sendEmail;

  delete data._emailTo;
  delete data._nombreCompleto;
  delete data._sendEmail;

  if (sheet.getLastRow() === 0) {
    sheet.appendRow(Object.keys(data));
  }
  sheet.appendRow(Object.values(data));

  // ── 2. ENVIAR EMAIL DE CONFIRMACIÓN ──
  if (sendEmail && emailTo) {
    const asunto = '¡Inscripción confirmada! Campus Sport Catarroja';
    const htmlEmail = buildEmailHtml(data, nombreCompleto);
    const textoPlano = buildEmailTexto(data, nombreCompleto);

    GmailApp.sendEmail(emailTo, asunto, textoPlano, {
      htmlBody: htmlEmail,
      name: 'Campus Sport Catarroja'
    });
  }

  return ContentService
    .createTextOutput(JSON.stringify({ ok: true }))
    .setMimeType(ContentService.MimeType.JSON);
}


// ── PLANTILLA HTML DEL EMAIL ──
